1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
11	export type Step = QuoteStep | ClaimStep;
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type QuoteResult = { premium: number };
19	export type ClaimResult = { payout: number; remainingCap: number };
20	export type StepResult = QuoteResult | ClaimResult;
21	export type ScenarioResult = { results: StepResult[] };
22	
23	const PROCESSING_FEE = 5;
24	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const INSURANCE_VALUES: Record<string, number> = {
36	  sword: 1000,
37	  amulet: 600,
38	  staff: 800,
39	  potion: 400,
40	  rune: 250,
41	  moonstone: 250,
42	};
43	
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	
47	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
48	const BLOCK_SIZE = 3;
49	const BLOCK_BASE_PREMIUM = 60;
50	
51	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
52	
53	const countByType = (items: Item[]): Record<string, number> => {
54	  const counts: Record<string, number> = {};
55	  for (const item of items) {
56	    counts[item.type] = (counts[item.type] ?? 0) + 1;
57	  }
58	  return counts;
59	};
60	
61	const componentGroupPremium = (type: string, count: number): number =>
62	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
63	
64	const itemsBasePremium = (items: Item[]): number => {
65	  const mainItems = items.filter((item) => !isComponent(item));
66	  const components = items.filter(isComponent);
67	  const mainTotal = mainItems.reduce(
68	    (sum, item) => sum + BASE_PREMIUMS[item.type],
69	    0,
70	  );
71	  const componentTotal = Object.entries(countByType(components)).reduce(
72	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
73	    0,
74	  );
75	  return mainTotal + componentTotal;
76	};
77	
78	const CURSE_SURCHARGE_RATE = 0.5;
79	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
80	const HIGH_ENCHANTMENT_THRESHOLD = 5;
81	
82	const itemModifiersSurcharge = (item: Item): number => {
83	  const base = BASE_PREMIUMS[item.type];
84	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
85	  const highEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
86	  return curse + highEnchantment;
87	};
88	
89	const sumItemModifiers = (items: Item[]): number =>
90	  items.reduce((sum, item) => sum + itemModifiersSurcharge(item), 0);
91	
92	const LOYALTY_DISCOUNT_RATE = 0.2;
93	const LOYALTY_YEARS_THRESHOLD = 2;
94	
95	const policyModifiersSurcharge = (basePremium: number, yearsWithMHPCO: number): number => {
96	  const firstContract = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
97	  const loyalty = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -basePremium * LOYALTY_DISCOUNT_RATE : 0;
98	  return firstContract + loyalty;
99	};
100	
101	const quoteStep = (step: QuoteStep, yearsWithMHPCO: number): QuoteResult => {
102	  const basePremium = itemsBasePremium(step.items);
103	  const itemModifiers = sumItemModifiers(step.items);
104	  const policyModifiers = policyModifiersSurcharge(basePremium, yearsWithMHPCO);
105	  const premium = basePremium + itemModifiers + policyModifiers + PROCESSING_FEE;
106	  return { premium: Math.ceil(premium) };
107	};
108	
109	type PolicyState = { items: Item[]; insuranceSum: number; remainingCap: number };
110	
111	const insuranceSum = (items: Item[]): number =>
112	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
113	
114	const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
115	  const policy = policies.get(step.policy)!;
116	  const totalPayout = step.incident.damages.reduce(
117	    (sum, dmg) => sum + (dmg.amount - DEDUCTIBLE),
118	    0,
119	  );
120	  policy.remainingCap -= totalPayout;
121	  return { payout: totalPayout, remainingCap: policy.remainingCap };
122	};
123	
124	export const runScenario = (scenario: Scenario): ScenarioResult => {
125	  const policies = new Map<number, PolicyState>();
126	  const results: StepResult[] = [];
127	  scenario.steps.forEach((step, idx) => {
128	    if (step.op === "quote") {
129	      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO));
130	      const sum = insuranceSum(step.items);
131	      policies.set(idx, { items: step.items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER });
132	    } else {
133	      results.push(claimStep(step, policies));
134	    }
135	  });
136	  return { results };
137	};
